using System;
using System.Net.Http;

public class Program
{
  public static void Main(string[] args)
  {
    string url = "https://docs.microsoft.com/en-us";

    // Create an HttpClient instance to make requests using the GET method
    var httpClient = new HttpClient();
    
    // Set up a response object, send the request and log the response status code. 
    HttpResponseMessage response = httpClient.GetAsync(url).Result;
    Console.WriteLine("Response Status Code: {0}", response.StatusCode);

    // Log other response metadata properties such as Content-Type or Date
    Console.WriteLine("Response Content Type: " + response.Content.Headers.ContentType.ToString());
    Console.WriteLine("Response Date:        " + response.Headers.Date.Value.ToString());
  }
}